						slack := float64(curr.TimeEnd-curr.TimeStart) - waitTime
						if slack < 0 {
							timeSlackPenalty -= slack * 10.0
						} else if slack < 30 {
							timeSlackPenalty += (30.0 - slack) * 0.5
						}
					}
					score := increase*0.8 + timeSlackPenalty*0.2
					if score < bestScore {
