func InsertShips(dispatch Dispatch, oris, dess []Station, total_ship int) Dispatch {
	candidateIndices := make([]int, 0, MAXASSIGNS)
	emptyIndices := make([]int, 0, MAXASSIGNS)
	for i := 0; i < dispatch.AssignsLen; i++ {
		if dispatch.Assigns[i].StationsLen > 0 {
			candidateIndices = append(candidateIndices, i)
		} else {
			emptyIndices = append(emptyIndices, i)
		}
	}
	rand.Shuffle(len(candidateIndices), func(i, j int) {
		candidateIndices[i], candidateIndices[j] = candidateIndices[j], candidateIndices[i]
	})
	allCandidateOrder := append(candidateIndices, emptyIndices...)
	for orderIdx := range oris {
		orderId := total_ship + orderIdx
		bestAssignIdx := -1
		bestDelta := math.Inf(1)
		var bestBackup Assign
		inserted := false
		for _, idx := range allCandidateOrder {
			if idx >= MAXASSIGNS {
				continue
			}
			currentAssign := &dispatch.Assigns[idx]
			backup := *currentAssign
			if currentAssign.AddShip(orderId, oris[orderIdx], dess[orderIdx]) {
				currentAssign.GenRoute()
				if currentAssign.Cost >= 0 {
					delta := currentAssign.Cost - backup.Cost
					if delta < bestDelta {
						bestDelta = delta
						bestAssignIdx = idx
						bestBackup = backup
						inserted = true
					}
				}
				currentAssign.RemoveShip(orderId)
				currentAssign.GenRoute()
			}
		}
		if inserted && bestAssignIdx != -1 {
			targetAssign := &dispatch.Assigns[bestAssignIdx]
			if targetAssign.AddShip(orderId, oris[orderIdx], dess[orderIdx]) {
				targetAssign.GenRoute()
				if targetAssign.Cost < 0 {
					dispatch.Assigns[bestAssignIdx] = bestBackup
				}
			}
		} else {
			fallbackOk := false
			for _, idx := range emptyIndices {
				if idx >= MAXASSIGNS || idx < dispatch.AssignsLen {
					continue
				}
				assignToUse := idx
				if idx >= dispatch.AssignsLen {
					assignToUse = dispatch.AssignsLen
				}
				if dispatch.Assigns[assignToUse].AddShip(orderId, oris[orderIdx], dess[orderIdx]) {
					dispatch.Assigns[assignToUse].GenRoute()
					if dispatch.Assigns[assignToUse].Cost >= 0 {
						if assignToUse == dispatch.AssignsLen {
							dispatch.AssignsLen++
						}
						fallbackOk = true
						break
					} else {
						dispatch.Assigns[assignToUse].RemoveShip(orderId)
						dispatch.Assigns[assignToUse].GenRoute()
					}
				}
			}
			if !fallbackOk && dispatch.AssignsLen < MAXASSIGNS {
				newIdx := dispatch.AssignsLen
				if dispatch.Assigns[newIdx].AddShip(orderId, oris[orderIdx], dess[orderIdx]) {
					dispatch.Assigns[newIdx].GenRoute()
					if dispatch.Assigns[newIdx].Cost >= 0 {
